+
+	commitTime, err := time.Parse("2006-01-02 15:04:05 -0700", commitTimeStr)
+	if err != nil {
+		d.logger.Printf("doctor_dog: jsonl backup check: cannot parse commit time %q: %v", commitTimeStr, err)
